# GOOGLE TTS 數據
LANG_GOOGLE = {
    "簡體中文 (zh-cn)": "zh-cn",
    "繁體中文 (zh-tw)": "zh-tw",
    "英文 (en)": "en"
}

# 風格預設 (僅 Edge 有效)
STYLE_PRESETS = {
    "general":      {"rate": 0,   "pitch": 0},
    "affectionate": {"rate": -25, "pitch": -5},
    "cheerful":     {"rate": 15,  "pitch": 5},
    "gentle":       {"rate": -10, "pitch": -2},
