            pitch = st.slider("音調 (Pitch)", -12, 12, 0, format="%d", help="後處理變調 (Semitones)。注意：會改變音色。")
            piper_noise = st.slider("語氣變化 (Noise)", 0.1, 1.0, 0.667, step=0.01, help="控制語音的隨機變化程度 (Noise Scale)")

