        silence_threshold = -70
        if remove_silence_opt:
            silence_threshold = st.slider("靜音判定閾值 (dB)", -80, -10, -70, step=5)

        # Status Bar
        if HAS_PYDUB and HAS_FFMPEG:
            status_html = '<div class="status-ok"><span>●</span> 環境完整'
            if HAS_PIPER: status_html += ' (+Piper)'
